import android.content.Context;
import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.io.OutputStream;
import java.net.HttpURLConnection;
import java.net.URL;
import javax.net.ssl.HttpsURLConnection;

public class HttpClient {

    private static final String LOCAL_NETWORK_PREFIX = "192.168.";
    
    public static String sendRequest(String urlString, String method, String payload, Context context) throws Exception {
        URL url = new URL(urlString);
        HttpURLConnection connection;

        if (urlString.startsWith("https://")) {
            connection = (HttpsURLConnection) url.openConnection();
        } else {
            connection = (HttpURLConnection) url.openConnection();
        }

        connection.setRequestMethod(method);
        connection.setRequestProperty("Content-Type", "application/json");
        connection.setDoOutput(true);

        if (payload != null) {
            try (OutputStream os = connection.getOutputStream()) {
                os.write(payload.getBytes());
                os.flush();
            }
        }

        int responseCode = connection.getResponseCode();
        StringBuilder response = new StringBuilder();

        if (responseCode == HttpURLConnection.HTTP_OK) {
            try (BufferedReader in = new BufferedReader(new InputStreamReader(connection.getInputStream()))) {
                String inputLine;
                while ((inputLine = in.readLine()) != null) {
                    response.append(inputLine);
                }
            }
        }

        connection.disconnect();
        return response.toString();
    }

    public static boolean isLocalNetwork(String ipAddress) {
        return ipAddress.startsWith(LOCAL_NETWORK_PREFIX);
    }
}